import{_ as e,o as r,c as t,ae as o}from"./chunks/framework.C23mN02-.js";const q=JSON.parse('{"title":"史部代表作者","description":"","frontmatter":{},"headers":[],"relativePath":"sucai/zuozhe/shi/史部作者.md","filePath":"sucai/zuozhe/shi/史部作者.md"}'),h={name:"sucai/zuozhe/shi/史部作者.md"};function i(l,a,n,d,s,u){return r(),t("div",null,[...a[0]||(a[0]=[o('<h1 id="史部代表作者" tabindex="-1">史部代表作者 <a class="header-anchor" href="#史部代表作者" aria-label="Permalink to &quot;史部代表作者&quot;">​</a></h1><h2 id="司马迁-约公元前145年" tabindex="-1">司马迁（约公元前145年-？） <a class="header-anchor" href="#司马迁-约公元前145年" aria-label="Permalink to &quot;司马迁（约公元前145年-？）&quot;">​</a></h2><p>字子长，西汉夏阳人，中国古代伟大的史学家、文学家。继父职任太史令，发愤著书，创作了中国第一部纪传体通史《史记》，被后人尊为&quot;史圣&quot;。</p><h2 id="班固-公元32年-92年" tabindex="-1">班固（公元32年-92年） <a class="header-anchor" href="#班固-公元32年-92年" aria-label="Permalink to &quot;班固（公元32年-92年）&quot;">​</a></h2><p>字孟坚，东汉扶风安陵人。继承父业，耗时二十余年完成《汉书》，是中国第一部纪传体断代史。与司马迁并称&quot;班马&quot;。</p><h2 id="司马光-1019年-1086年" tabindex="-1">司马光（1019年-1086年） <a class="header-anchor" href="#司马光-1019年-1086年" aria-label="Permalink to &quot;司马光（1019年-1086年）&quot;">​</a></h2><p>字君实，号迂叟，北宋陕州夏县人。主编《资治通鉴》，上起战国下终五代，共二百九十四卷，是中国第一部编年体通史。</p><h2 id="陈寿-233年-297年" tabindex="-1">陈寿（233年-297年） <a class="header-anchor" href="#陈寿-233年-297年" aria-label="Permalink to &quot;陈寿（233年-297年）&quot;">​</a></h2><p>字承祚，西晋巴西安汉人。著《三国志》，记载三国时期魏、蜀、吴历史，与《史记》《汉书》《后汉书》合称&quot;前四史&quot;。</p><h2 id="范晔-398年-445年" tabindex="-1">范晔（398年-445年） <a class="header-anchor" href="#范晔-398年-445年" aria-label="Permalink to &quot;范晔（398年-445年）&quot;">​</a></h2><p>字蔚宗，南朝宋顺阳人。著《后汉书》，记述东汉历史的纪传体史书，&quot;前四史&quot;之一。</p><h2 id="刘向-约公元前77年-公元前6年" tabindex="-1">刘向（约公元前77年-公元前6年） <a class="header-anchor" href="#刘向-约公元前77年-公元前6年" aria-label="Permalink to &quot;刘向（约公元前77年-公元前6年）&quot;">​</a></h2><p>字子政，西汉沛县人。整理古籍，编订《战国策》《说苑》等，对中国文献学有重大贡献。</p><h2 id="荀悦-148年-209年" tabindex="-1">荀悦（148年-209年） <a class="header-anchor" href="#荀悦-148年-209年" aria-label="Permalink to &quot;荀悦（148年-209年）&quot;">​</a></h2><p>字仲豫，东汉颍川颍阴人。著《汉纪》，为编年体断代史典范，对后世编年史影响深远。</p><h2 id="欧阳修-1007年-1072年" tabindex="-1">欧阳修（1007年-1072年） <a class="header-anchor" href="#欧阳修-1007年-1072年" aria-label="Permalink to &quot;欧阳修（1007年-1072年）&quot;">​</a></h2><p>字永叔，号醉翁，北宋吉州永丰人。领导北宋古文运动，主修《新唐书》，独撰《新五代史》。</p><h2 id="司马彪-306年" tabindex="-1">司马彪（？-306年） <a class="header-anchor" href="#司马彪-306年" aria-label="Permalink to &quot;司马彪（？-306年）&quot;">​</a></h2><p>字绍统，西晋宗室。著《续汉书》，记载东汉至西晋的历史，史料价值极高。</p><h2 id="赵晔" tabindex="-1">赵晔 <a class="header-anchor" href="#赵晔" aria-label="Permalink to &quot;赵晔&quot;">​</a></h2><p>字长君，东汉会稽山阴人。著《吴越春秋》，记述吴越两国历史，是研究吴越文化的重要史料。</p><h2 id="袁枢-1131年-1205年" tabindex="-1">袁枢（1131年-1205年） <a class="header-anchor" href="#袁枢-1131年-1205年" aria-label="Permalink to &quot;袁枢（1131年-1205年）&quot;">​</a></h2><p>字机仲，南宋建安人。编《通鉴纪事本末》，创立&quot;纪事本末体&quot;，是中国史学三大体裁之一。</p><h2 id="顾炎武-1613年-1682年" tabindex="-1">顾炎武（1613年-1682年） <a class="header-anchor" href="#顾炎武-1613年-1682年" aria-label="Permalink to &quot;顾炎武（1613年-1682年）&quot;">​</a></h2><p>字忠清，号亭林，明末清初苏州府昆山县人。与黄宗羲、王夫之并称&quot;明末清初三大儒&quot;，著《日知录》《天下郡国利病书》。</p><h2 id="黄宗羲-1610年-1695年" tabindex="-1">黄宗羲（1610年-1695年） <a class="header-anchor" href="#黄宗羲-1610年-1695年" aria-label="Permalink to &quot;黄宗羲（1610年-1695年）&quot;">​</a></h2><p>字太冲，号南雷，明末清初绍兴府余姚县人。思想家、史学家，著《明夷待访录》《宋元学案》。</p><h2 id="王夫之-1619年-1692年" tabindex="-1">王夫之（1619年-1692年） <a class="header-anchor" href="#王夫之-1619年-1692年" aria-label="Permalink to &quot;王夫之（1619年-1692年）&quot;">​</a></h2><p>字而农，号姜斋，明末清初衡州府衡阳县人。著《读通鉴论》《宋论》，为中国古典史论集大成之作。</p><h2 id="曾国藩-1811年-1872年" tabindex="-1">曾国藩（1811年-1872年） <a class="header-anchor" href="#曾国藩-1811年-1872年" aria-label="Permalink to &quot;曾国藩（1811年-1872年）&quot;">​</a></h2><p>字伯涵，号涤生，清代湖南湘乡人。编《经史百家杂钞》，选编《十八家诗钞》，在文学与史学上均有贡献。</p><h2 id="赵尔巽-1844年-1927年" tabindex="-1">赵尔巽（1844年-1927年） <a class="header-anchor" href="#赵尔巽-1844年-1927年" aria-label="Permalink to &quot;赵尔巽（1844年-1927年）&quot;">​</a></h2><p>字公骕，号次珊，清代奉天铁岭人。主编《清史稿》，记述清代历史的未定稿史料。</p><h2 id="钱穆-1895年-1990年" tabindex="-1">钱穆（1895年-1990年） <a class="header-anchor" href="#钱穆-1895年-1990年" aria-label="Permalink to &quot;钱穆（1895年-1990年）&quot;">​</a></h2><p>字宾四，中国现代著名历史学家。著《国史大纲》《中国历代政治得失》，为中国现代史学奠基人之一。</p><h2 id="吕思勉-1884年-1957年" tabindex="-1">吕思勉（1884年-1957年） <a class="header-anchor" href="#吕思勉-1884年-1957年" aria-label="Permalink to &quot;吕思勉（1884年-1957年）&quot;">​</a></h2><p>字诚之，中国现代著名历史学家。著《吕著中国通史》《白话本国史》，以夹叙夹议风格著称。</p><h2 id="陈寅恪-1890年-1969年" tabindex="-1">陈寅恪（1890年-1969年） <a class="header-anchor" href="#陈寅恪-1890年-1969年" aria-label="Permalink to &quot;陈寅恪（1890年-1969年）&quot;">​</a></h2><p>字鹤寿，中国现代最负盛名的历史学家之一。通晓十余种文字，对魏晋南北朝史、隋唐史、敦煌学贡献巨大。</p><h2 id="郭沫若-1892年-1978年" tabindex="-1">郭沫若（1892年-1978年） <a class="header-anchor" href="#郭沫若-1892年-1978年" aria-label="Permalink to &quot;郭沫若（1892年-1978年）&quot;">​</a></h2><p>原名开贞，字鼎堂，中国现代著名文学家、历史学家。著《甲骨文合集》《两周金文辞大系》，开创新中国考古学与古文字学。</p>',41)])])}const p=e(h,[["render",i]]);export{q as __pageData,p as default};
